<?php
namespace App\Http\Controllers;
use App\Models\User; use App\Models\PlayerStat; use App\Services\SteamAuthService; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\Auth; use Illuminate\Support\Str; use Throwable;
class SteamAuthController extends Controller { public function redirect(Request $request,SteamAuthService $steam):RedirectResponse{return redirect()->away($steam->redirectUrl($request));} public function callback(Request $request,SteamAuthService $steam):RedirectResponse{try{$id=$steam->verify($request);$profile=$steam->profile($id);$user=User::updateOrCreate(['steam_id'=>$id],['name'=>$profile['personaname']??'Steam Player','email'=>$id.'@steam.nexus.local','password'=>Str::random(48),'avatar_url'=>$profile['avatarfull']??null,'profile_url'=>$profile['profileurl']??null,'last_login_at'=>now()]);PlayerStat::firstOrCreate(['user_id'=>$user->id,'game_server_id'=>null]);abort_if(in_array($user->status,['suspended','banned'],true),403);Auth::login($user,true);$request->session()->regenerate();return redirect()->intended(route('profile.show',$user));}catch(Throwable $e){report($e);return redirect()->route('login')->withErrors(['steam'=>'Steam входът не бе потвърден. Опитай отново.']);}} }
